#!/usr/bin/expect -f
set timeout 20
spawn telnet 127.0.0.1 9001
expect {
  timeout { puts "\n[[TIMEOUT]]"; exit 0 }
  eof { puts "\n[[EOF]]"; exit 0 }
}

